INSERT INTO public.passages VALUES ('b58bb246-047d-48e5-843b-1ecc19bb07b9', '9129ee0c-7348-4c67-b4b1-8bc9f64f6945', 'SECTION 1', '<p><strong>Read and answer Questions 1-7.</strong></p>
<p><span style="font-size: 14pt;"><strong data-path-to-node="4" data-index-in-node="0">A. ‘GET GOING!’</strong></span></p>
<p><strong data-path-to-node="5" data-index-in-node="0">Car playing up?</strong></p>
<p><strong data-path-to-node="5" data-index-in-node="16">Mobile car repairs</strong></p>
<p>– We come to you – day or night</p>
